  class Square: Shape { init(sideLength: Double, name: String) { self.sideLength = sideLength super.init(name: name) numberOfSides = 4 } func area() -&gt; Double { return sideLength * sideLength } override func simpleDescription() -&gt; String { return &#34;A square with sides of length \(sideLength).&#34; } var sideLength: Double}let shape = Square(sideLength: 5.2, name: &#34;My square&#34;)
